@router.post("/users", response_model=UserResponse, status_code=201)
async def create_user(
    request: CreateUserRequest,
    use_case: CreateUserUseCase = Depends(get_create_user_use_case),
):
    try:
        output = await use_case.execute(CreateUserInput(name=request.name, email=request.email))
        return UserResponse.from_dto(output.user)
    except ApplicationError as e:
        raise HTTPException(status_code=400, detail=str(e))

from sqlalchemy import Column, String from sqlalchemy.orm import declarative_base
Base = declarative_base()
class User(Base): # Domain entity inheriting from ORM base — violation __tablename__ = "users" email = Column(String, unique=True)
